INSERT INTO knowledge_doc (title, content, source, dept_code, status, deleted, create_time) VALUES
('遂宁市学生资助政策说明', '遂宁市实施全面的学生资助政策，涵盖学前教育、义务教育、高中教育和高等教育各阶段。家庭经济困难学生可申请国家助学金、奖学金、助学贷款等多种资助形式。义务教育阶段实行两免一补政策，即免杂费、免书本费、补助寄宿生生活费。', '市教育局', 'EDU', 1, 0, NOW()),
('遂宁市健康证明办理指南', '遂宁市健康证明办理可在各区县人民医院或社区卫生服务中心进行。办理时需携带本人身份证、近期一寸免冠照片。健康检查项目包括内科、外科、肝功能、胸透等。健康证明有效期为一年，到期需重新体检。办理时限为体检合格后3个工作日内。', '市卫健委', 'HEA', 1, 0, NOW()),
('遂宁市政府信息公开实施办法', '遂宁市政府信息公开遵循公正、公平、便民原则。主动公开政府信息通过政府网站、公报、新闻发布会等渠道。公民法人可申请获取特定政府信息，行政机关应当自收到申请之日起20个工作日内予以答复。涉及商业秘密、个人隐私的政府信息不予公开。', '市政府办公厅', 'GOV', 1, 0, NOW()),
('遂宁市社保参保登记指南', '遂宁市社会保险参保登记包括养老保险、医疗保险、失业保险、工伤保险和生育保险。用人单位应当自用工之日起30日内为职工办理社会保险登记。灵活就业人员可直接到社保经办机构办理参保登记。参保需提交身份证、户口本等材料。', '市人社局', 'SOC', 1, 0, NOW()),
('遂宁市住房公积金提取条件', '遂宁市住房公积金提取条件包括：购买自住住房、偿还购房贷款本息、租赁住房、离退休、完全丧失劳动能力并与单位终止劳动关系、出境定居等情形。职工提取公积金需提供相关证明材料，经审批后资金划入个人账户。', '市住建局', 'HOU', 1, 0, NOW()),
('遂宁市优化营商环境措施', '遂宁市出台优化营商环境若干措施，包括简化企业开办流程、压缩工程建设项目审批时间、提升获得电力便利度、优化不动产登记流程、简化税费缴纳程序等。目标打造市场化法治化国际化营商环境，激发市场主体活力。', '市政府办公厅', 'GOV', 1, 0, NOW()),
('遂宁市义务教育招生政策', '遂宁市义务教育招生坚持免试就近入学原则。小学入学年龄为年满6周岁，初中入学为小学毕业生。随迁子女入学以居住证为主要依据，保障符合条件的随迁子女平等接受义务教育。严禁以各类考试、竞赛、培训成绩或证书证明等作为招生依据。', '市教育局', 'EDU', 1, 0, NOW()),
('遂宁市医疗保障政策说明', '遂宁市基本医疗保险覆盖城镇职工和城乡居民两大类。职工医保由用人单位和职工共同缴纳，居民医保实行个人缴费与政府补贴相结合。参保人员在规定医疗机构就医可享受门诊统筹、住院报销、大病保险等待遇。异地就医需提前办理备案手续。', '市医保局', 'HEA', 1, 0, NOW());
